import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const LeagueGeneration = () => {
    const [clasificaciones, setClasificaciones] = useState({});
    const [calendarios, setCalendarios] = useState({});
    const navigate = useNavigate();

    const mezclarEquipos = (equipos) => {
        const copia = [...equipos];
        for (let i = copia.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [copia[i], copia[j]] = [copia[j], copia[i]];
        }
        return copia;
    };

    const agruparPorLiga = (equipos) => {
        return equipos.reduce((ligas, equipo) => {
            const { liga } = equipo;
            if (!ligas[liga]) {
                ligas[liga] = [];
            }
            ligas[liga].push(equipo);
            return ligas;
        }, {});
    };

    const generarClasificacion = (equipos) => {
        return equipos.map((equipo) => ({
            id: equipo.id,
            imagen: equipo.imagen,
            nombre: equipo.nombre,
            puntos: 0,
            partidosJugados: 0,
            victorias: 0,
            empates: 0,
            derrotas: 0,
            golesFavor: 0,
            golesContra: 0,
            diferenciaGoles: 0,
        }));
    };

    const generarJornadasLiga = (equipos) => {
        if (equipos.length % 2 !== 0) {
            equipos.push({ id: -1, nombre: "Descanso" });
        }

        const n = equipos.length;
        const mitad = n / 2;
        const jornadas = [];

        const rotacion = equipos.slice(1); // el primer equipo se mantiene fijo

        for (let i = 0; i < n - 1; i++) {
            const jornada = [];

            const izquierda = [equipos[0], ...rotacion.slice(0, mitad - 1)];
            const derecha = rotacion.slice(mitad - 1).reverse();

            for (let j = 0; j < mitad; j++) {
                let local, visitante;

                if (i % 2 === 0) {
                    local = izquierda[j];
                    visitante = derecha[j];
                } else {
                    local = derecha[j];
                    visitante = izquierda[j];
                }

                if (local.id !== -1 && visitante.id !== -1) {
                    jornada.push({ local, visitante });
                }
            }
            jornadas.push(jornada);
            rotacion.unshift(rotacion.pop());
        }

        const jornadasVuelta = jornadas.map((jornada) =>
            jornada.map(({ local, visitante }) => ({
                local: visitante,
                visitante: local,
            }))
        );

        return [...jornadas, ...jornadasVuelta];
    };

    useEffect(() => {
        // Limpiar localStorage para reiniciar los datos
        localStorage.removeItem("equipos");
        localStorage.removeItem("clasificaciones");
        localStorage.removeItem("calendarios");
    
        const equiposAlmacenados = JSON.parse(localStorage.getItem("equipos"));
        const ligasAgrupadas = agruparPorLiga(equiposAlmacenados);
    
        const nuevasClasificaciones = {};
        const nuevosCalendarios = {};
    
        for (const liga in ligasAgrupadas) {
            const equiposLiga = mezclarEquipos(ligasAgrupadas[liga]);
            nuevasClasificaciones[liga] = generarClasificacion(equiposLiga);
            nuevosCalendarios[liga] = generarJornadasLiga([...equiposLiga]);
        }
    
        setClasificaciones(nuevasClasificaciones);
        setCalendarios(nuevosCalendarios);
    
        // Guardar las nuevas clasificaciones y calendarios en localStorage
        localStorage.setItem("clasificaciones", JSON.stringify(nuevasClasificaciones));
        localStorage.setItem("calendarios", JSON.stringify(nuevosCalendarios));
    }, []);
    
    const handleContinue = () => {
        navigate("/main-menu");
    };

    return (
        <div className="league-generation">
            <h1>Ligas Generadas</h1>
            <ul>
                {Object.keys(clasificaciones).map((liga) => (
                    <li key={liga}>{liga}</li>
                ))}
            </ul>
            <button onClick={handleContinue}>Continuar</button>
        </div>
    );
};

export default LeagueGeneration;
